    it('should NOT include dataVisibility in query keys', async () => {
      const FinancialOverview = (await import('../../../client/src/pages/dashboard/overview')).default;

      render(
        <TestWrapper>
          <FinancialOverview />
        </TestWrapper>
      );

      // Wait for component to fully render and queries to be created
      await waitFor(() => {
        const graphCards = screen.getAllByTestId(/^card-budget-graph-/);
        expect(graphCards).toHaveLength(3);
      }, { timeout: 5000 });

      // Give queries time to be registered in the cache
      await new Promise(resolve => setTimeout(resolve, 100));

      // Inspect the actual query client to check query keys
      const queryCache = testQueryClient.getQueryCache();
      const allQueries = queryCache.getAll();
      
      // Filter forecast queries
      const forecastQueries = allQueries.filter(query => 
        query.queryKey[0] === '/api/budgets/forecast'
      );
      
      // Should have exactly 3 forecast queries (one per building)
      expect(forecastQueries).toHaveLength(3);
      
      // Verify query keys contain the expected parameters
      forecastQueries.forEach(query => {
        const queryKey = query.queryKey as any[];
        
        // Should contain: ['/api/budgets/forecast', buildingId, viewType, periodLength, startMonth, startYear]
        expect(queryKey).toHaveLength(6);
        expect(queryKey[0]).toBe('/api/budgets/forecast');
        expect(['building-1', 'building-2', 'building-3']).toContain(queryKey[1]);
        expect(queryKey[2]).toBe('month'); // viewType
        expect(typeof queryKey[3]).toBe('number'); // periodLength
        expect(typeof queryKey[4]).toBe('number'); // startMonth
        expect(typeof queryKey[5]).toBe('number'); // startYear
        
        // Verify dataVisibility is NOT in the query key
        const keyString = JSON.stringify(queryKey);
        expect(keyString).not.toContain('dataVisibility');
      });
      
      // Also verify project queries
      const projectQueries = allQueries.filter(query => 
        query.queryKey[0] === '/api/maintenance/buildings'
      );
      
      // Should have exactly 3 project queries
      expect(projectQueries).toHaveLength(3);
      
      projectQueries.forEach(query => {
        const queryKey = query.queryKey as any[];
        
        // Should contain: ['/api/maintenance/buildings', buildingId, 'projects']
        expect(queryKey).toHaveLength(3);
        expect(queryKey[0]).toBe('/api/maintenance/buildings');
        expect(['building-1', 'building-2', 'building-3']).toContain(queryKey[1]);
        expect(queryKey[2]).toBe('projects');
      });
    });

